<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
    </template>
    
    <script>
    import DataServices from "../../services/DataService";
    import ReportViewer from './ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                reportPath: null,
                parameter: [],
                FindalLocationArray: [],
                isLoading: false,
                FormSchema: [{
                        layoutType: "triple",
                        Data: [
                        {
                                astype: "MultiSelectField",
                                label: this.$t("Job Title (Department)"),
                                name: "JobTitle",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('JobTitle'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Status"),
                                name: "Status",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Status'),
                                mode: "tag",
                                config: {
                                    options: [],

                                },
                            },
                            
                            
                            {
                            astype: "RadioField",
                            label: this.$t('Group By'),
                            name: "GroupBy",
                            value: "Designation",
                            placeholder: "",
                            config: {
                                options: [{
                                    name: 'Designation', value: 'Designation'
                                }, {
                                    name: "Status", value: 'Status'
                                }],
                                onChange:this.LoadCompanies,
                                showAddIcon: false
                            },
                            validationRules: { "required": true },
                        },
                            
                        ],
                    },
                    
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            var vm = this;
            vm.DataLoaded = 1;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            await vm.BindJobs();
            await vm.BindStatus();
        },
        methods:{
            ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';      
        },
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
            var vm = this;
            vm.isLoading=true;
            vm.reportPath = '';      
            vm.parameter=[];
            let myObj = {
                reportName: "jobposthirringreport",
                StatusIds:  e.Status.length > 0 ? e.Status.map(item => item.value).join(",") : '',
                PostIds: e.JobTitle.length > 0 ? e.JobTitle.map(item => item.value).join(",") : '',
                GroupBy:  e.GroupBy,
            }
            var postString = JSON.stringify(myObj);   
             DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.ReportPath;
                vm.parameter = response.data.parameters;
            })
            vm.isLoading=false;
        },
        BindJobs: async function () {
            var vm = this;
            await DataServices.GetPost().then((response) => {
                if (response.data.length > 0) {
                    var DepartmentData = response.data;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.POST_TITLE,
                            value: element.POST_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        BindStatus: async function () {
            var vm = this;
            var url = `langCode=en&companyId=${vm.companyId}&statusType=JobApplicant&hasglobal=`;
            await DataServices.GetStatusList(url).then((response) => {
                if (response.data.length > 0) {
                    var StatusData = response.data;
                    StatusData.forEach(element => {
                        var Obj = {
                            name: element.STATUS,
                            value: element.STATUS_ID
                        }
                        vm.FormSchema[0].Data[1].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        }
        }
    };
    </script>
    